/**
 * Snapshot freshness loop. Story 133.
 *
 * Two operations:
 *   - `refreshIfStale()` — cheap `/snapshot/info` check, then pull binary
 *     snapshot only if the server's generation is newer than what the local
 *     DB represents. The local DB is replaced only when there are no
 *     pending changes (snapshot import would lose them).
 *   - `markDirty()` — fire-and-forget debounced trigger for trigger 1
 *     (post-write). Simplest possible debounce: a module-level boolean
 *     `scheduled`. While truthy, subsequent calls are no-ops. The timer
 *     callback clears the flag and calls `refreshIfStale()`.
 *
 * Triggers 2-4 (online, visibilitychange, periodicsync) call
 * `refreshIfStale()` directly — they're idempotent already; only the
 * post-write path bursts and benefits from debouncing.
 *
 * Storage choice: the "last applied generation" lives in the local OPFS
 * `settings.sync.snapshot_generation` row — the snapshot import brings the
 * server's generation along with it, so the local row literally records
 * "the generation this client's DB represents." No separate per-origin IDB
 * store is needed. The shared `createSnapshotMetaRepository` is used for
 * both the server-side write and the client-side read.
 */

import { createSnapshotMetaRepository, type SnapshotInfoBody } from '@motivation/shared';
import { API_URL } from '../../config.js';
import { DbService } from '../../db/db.service.js';
import { downloadAndLoadSnapshot } from '../../db/db-snapshot.service.js';
import { SyncService } from './sync.service.js';
import { createComponentLogger } from '../../utils/component-logger.js';

const log = createComponentLogger('snapshot-refresh');

export type RefreshResult =
    | { status: 'fresh' }
    | { status: 'updated'; from: number; to: number }
    | { status: 'pending'; pendingCount: number }
    | { status: 'offline' }
    | { status: 'failed'; error: string };

export interface RefreshOptions {
    fetchImpl?: typeof fetch;
    dbService?: DbService;
}

const MARK_DIRTY_DELAY_MS = 2000;
// `scheduled` is a plain boolean rather than a timer ID because the boolean
// is set *before* `setTimeout(...)` is called and cleared inside the callback
// — so even a synchronous-firing test shim (or any unusual scheduler) leaves
// the flag in a coherent state. A timer-ID-only check has a race: the ID
// assignment happens after `setTimeout` returns, which can race with a
// synchronously-firing callback that already cleared it.
let scheduled = false;

async function fetchSnapshotInfo(fetchImpl: typeof fetch): Promise<SnapshotInfoBody> {
    const response = await fetchImpl(`${API_URL}/api/sync/snapshot/info`, {
        method: 'GET',
        cache: 'no-store',
    });
    if (!response.ok) {
        throw new Error(`snapshot/info: HTTP ${response.status} ${response.statusText}`);
    }
    return await response.json() as SnapshotInfoBody;
}

/**
 * Check the server's snapshot generation and download the binary snapshot
 * only if it's newer than what the local DB represents. Refuses to import
 * when the local DB has pending changes (snapshot replace would discard them).
 *
 * Never throws — failures return a structured `RefreshResult` so the four
 * triggers can call this in fire-and-forget fashion without worrying.
 */
export async function refreshIfStale(options: RefreshOptions = {}): Promise<RefreshResult> {
    const fetchImpl = options.fetchImpl ?? fetch;
    const dbService = options.dbService ?? DbService.getInstance();

    try {
        const pending = await SyncService.getPendingCount(dbService.driver);
        if (pending > 0) {
            log.debug('refreshIfStale: pending changes present, skipping snapshot import', { pending });
            return { status: 'pending', pendingCount: pending };
        }

        const localMeta = createSnapshotMetaRepository(dbService.driver);
        const local = await localMeta.readInfo();
        const info = await fetchSnapshotInfo(fetchImpl);
        log.debug('refreshIfStale: info', { local: local.generation, server: info.generation });

        if (info.generation <= local.generation) {
            return { status: 'fresh' };
        }

        // Server is newer — pull the binary snapshot and apply. The imported
        // snapshot brings the new `sync.snapshot_generation` value with it,
        // so we don't need to write back ourselves.
        const applied = await downloadAndLoadSnapshot({
            dbService,
            fetchImpl,
            preLoadCheck: async () => {
                // Last-chance guard: a write that arrived during the download
                // would otherwise be discarded. Same hook syncPendingChanges uses.
                const latestPending = await SyncService.getPendingCount(dbService.driver);
                return latestPending === 0;
            },
        });

        if (!applied) {
            // preLoadCheck vetoed — a pending change appeared mid-download.
            // Any other failure throws and is handled by the outer catch.
            const pendingCount = await SyncService.getPendingCount(dbService.driver);
            return { status: 'pending', pendingCount };
        }

        log.info('refreshIfStale: snapshot updated', { from: local.generation, to: info.generation });
        return { status: 'updated', from: local.generation, to: info.generation };
    } catch (error) {
        if (!navigator.onLine) {
            log.debug('refreshIfStale: navigator.onLine === false, treating as offline');
            return { status: 'offline' };
        }
        const message = error instanceof Error ? error.message : String(error);
        log.warn('refreshIfStale failed:', message);
        return { status: 'failed', error: message };
    }
}

/**
 * Schedule a refresh ~2 s from now, debounced. Subsequent calls within
 * the window are no-ops. Fire-and-forget — never awaited, never throws.
 *
 * Used by trigger 1 (the SW posts `snapshot:mark-dirty` after a successful
 * non-GET response; the main-thread bridge calls this).
 */
export function markDirty(): void {
    if (scheduled) return;
    scheduled = true;
    setTimeout(() => {
        scheduled = false;
        void refreshIfStale();
    }, MARK_DIRTY_DELAY_MS);
}

/** Test-only: reset the debounce flag. */
export function resetMarkDirtyTimerForTests(): void {
    scheduled = false;
}
